class Solution:
    def canBeEqual(self, s1: str, s2: str) -> bool:
        # Check if characters at positions 0 and 2 can be swapped
        # Check if characters at positions 1 and 3 can be swapped
        # Since we can perform these operations any number of times,
        # we can rearrange characters at positions 0 and 2 independently
        # and characters at positions 1 and 3 independently.
        return sorted(s1[::2]) == sorted(s2[::2]) and sorted(s1[1::2]) == sorted(s2[1::2])
